// src/components/StudentNavbar.jsx
import React from 'react';
import { NavLink, Link } from 'react-router-dom';

export default function StudentNavbar({ user, logout }) {
  const name = user?.name || 'Student';
  const initials = name.split(' ').map(w => w[0]).join('').toUpperCase().slice(0, 2);

  return (
    <nav className="student-nav">
      <div className="s-nav__left">
        <Link to="/student" className="navbar__logo">
          <span className="navbar__logo-icon">◈</span>
          <span>Launch<span style={{ color: 'var(--lavender)' }}>pad</span></span>
        </Link>
        <div className="s-nav__links">
          <NavLink to="/student" end className={({ isActive }) => `s-nav__link ${isActive ? 'active' : ''}`}>Home</NavLink>
          <NavLink to="/student/browse" className={({ isActive }) => `s-nav__link ${isActive ? 'active' : ''}`}>Browse</NavLink>
          <NavLink to="/student/applications" className={({ isActive }) => `s-nav__link ${isActive ? 'active' : ''}`}>Applications</NavLink>
          <NavLink to="/student/trainings" className={({ isActive }) => `s-nav__link ${isActive ? 'active' : ''}`}>Trainings</NavLink>
        </div>
      </div>
      <div className="s-nav__user">
        <NavLink to="/student/profile" className={({ isActive }) => `s-nav__link ${isActive ? 'active' : ''}`}>My Profile</NavLink>
        <Link to="/student/profile" className="s-avatar" title={name}>{initials}</Link>
        <button onClick={logout} className="btn btn-ghost btn-sm">Log out</button>
      </div>
    </nav>
  );
}
